import {{ Injectable }} from '@nestjs/common';
import {{ FeatureService }} from './models/feature.model';
import {{ FeatureServiceRepository }} from './repositories/feature.repository';

@Injectable()
export class FeatureServiceService {{
  constructor(
    private readonly repository: FeatureServiceRepository,
  ) {{}}

  async findAll(): Promise<FeatureService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<FeatureService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<FeatureService>): Promise<FeatureService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<FeatureService>): Promise<FeatureService> {{
    return this.repository.update(id, data);
  }}
}}

